// Extract search results and build context for LLM
const searchResponse = $input.first().json;
const hits = searchResponse.body?.result?.hits || [];
const queryText = $('Query Webhook').first().json.body.query_text;
const queryId = $('Query Webhook').first().json.body.query_id;

const citations = hits.map((hit, idx) => ({
  position: idx + 1,
  article_id: hit.fields.article_id,
  title: hit.fields.title,
  source: hit.fields.source,
  source_slug: hit.fields.source_slug,
  published_at: hit.fields.published_at,
  url: hit.fields.url,
  content: hit.fields.content,
  relevance_score: Math.round((hit._score || 0) * 100)
}));

const context = citations.map(c => 
  `[${c.position}] ${c.source} (${c.published_at}): ${c.title}\n${c.content}`
).join('\n\n');

return [{
  json: {
    query_text: queryText,
    query_id: queryId,
    context,
    citations
  }
}];

