// Build final response
const llmResponse = $input.first().json;
const contextData = $('Prepare Context').first().json;
const analysisContent = llmResponse.body?.content?.[0]?.text || 'Analysis unavailable.';

// Calculate confidence from citation relevance scores
const avgScore = contextData.citations.length > 0 ? contextData.citations.reduce((s, c) => s + (c.relevance_score || 0), 0) / contextData.citations.length : 0;
const confidence = Math.min(100, Math.round(avgScore * 100));

const response = {
  query_id: contextData.query_id,
  analysis: {
    content: analysisContent,
    confidence,
    primary_source_count: contextData.citations.length,
    supporting_source_count: 0
  },
  citations: contextData.citations.map(c => ({
    article_id: c.article_id,
    title: c.title,
    source_name: c.source,
    source_slug: c.source_slug,
    published_at: c.published_at,
    url: c.url,
    excerpt: c.content.substring(0, 200) + '...',
    relevance_score: c.relevance_score,
    position: c.position
  }))
};

return [{ json: response }];
